const images = collectMessageImages(chatJid, messagesToSend);
const imagesForAgent = images.length > 0 ? images : undefined;

// Determine the IM source JID for route update on successful injection
const lastSourceJidForRoute =
  messagesToSend[messagesToSend.length - 1]?.source_jid || chatJid;

// Cross-channel IM guard: when a message arrives from a different IM
// channel than the running process's current reply route, IPC injection
// would switch the route and cause in-flight replies to go to the wrong
// channel. Instead, close stdin and enqueue a fresh start so the new
// message gets its own processGroupMessages with correct routing.
const newImChannel = getChannelType(lastSourceJidForRoute);
const currentRoute = activeImReplyRoutes.get(group.folder);
const currentImChannel = currentRoute
  ? getChannelType(currentRoute)
  : null;

if (newImChannel && currentImChannel && newImChannel !== currentImChannel) {
  queue.closeStdin(chatJid);
  queue.enqueueMessageCheck(chatJid);
  logger.info(
    {
      chatJid,
      folder: group.folder,
      currentRoute,
      currentImChannel,
      newImChannel,
    },
